display.text:
import { component$, useStylesScoped$ } from "@builder.io/qwik";
import {
  routeLoader$,
  type DocumentHead,
  Link,
} from "@builder.io/qwik-city";
import { api } from "../../../../convex/_generated/api";
import { ConvexHttpClient } from "convex/browser";

/**
 * Public reader for a published piece. Anyone with the URL can read;
 * there is no auth, no editor, and no chrome beyond the page itself.
 * The styling matches the editorial theme but the page is static —
 * the only client-side behaviour is the masthead link back to Twyne.
 */

interface PublicDoc {
  title: string;
  authorName: string | null;
  briefSummary: string | null;
  content: string;
  publishedAt: number;
  updatedAt: number;
  slug: string;
}

export const usePublishedDoc = routeLoader$(async ({ params, status }) => {
  const slug = params.slug;
  if (!slug) {
    status(404);
    return null;
  }
  const convexUrl =
    (import.meta.env.PUBLIC_CONVEX_URL as string | undefined) ??
    (import.meta.env.VITE_CONVEX_URL as string | undefined);
  if (!convexUrl) {
    status(503);
    return null;
  }
  const client = new ConvexHttpClient(convexUrl);
  try {
    const doc = (await client.query(api.published.getBySlug, {
      slug,
    })) as PublicDoc | null;
    if (!doc) {
      status(404);
      return null;
    }
    return doc;
  } catch {
    status(500);
    return null;
  }
});

export default component$(() => {
  useStylesScoped$(`
    .reader {
      max-width: 38rem;
      margin: 4rem auto;
      padding: 0 1.5rem 6rem;
      color: #1a1611;
      font-family: ui-serif, Georgia, "Times New Roman", serif;
      line-height: 1.7;
    }
    .reader h1 {
      font-size: 2.4rem;
      font-weight: 600;
      line-height: 1.15;
      margin: 0 0 0.5rem;
      letter-spacing: -0.01em;
    }
    .reader .byline {
      font-family: ui-monospace, "SF Mono", monospace;
      font-size: 0.78rem;
      color: #6a5d4a;
      letter-spacing: 0.16em;
      text-transform: uppercase;
      margin: 0 0 2.5rem;
    }
    .reader .summary {
      border-left: 3px solid #b04a3a;
      padding: 0.2rem 0 0.2rem 1.2rem;
      font-style: italic;
      color: #4a3e30;
      margin: 0 0 2.5rem;
    }
    .reader h2 { font-size: 1.5rem; margin-top: 2.4rem; }
    .reader h3 { font-size: 1.2rem; margin-top: 2rem; }
    .reader p { margin: 0 0 1.1rem; }
    .reader blockquote {
      border-left: 3px solid #b04a3a;
      padding-left: 1rem;
      color: #4a3e30;
      font-style: italic;
      margin: 1.5rem 0;
    }
    .reader hr {
      border: none;
      border-top: 1px solid #c7b89c;
      margin: 2.4rem 0;
    }
    .reader a { color: #8b2f24; }
    .reader figure { margin: 1.5rem 0; }
    .reader img { max-width: 100%; height: auto; }
    .masthead {
      max-width: 38rem;
      margin: 2.5rem auto 0;
      padding: 0 1.5rem;
      display: flex;
      justify-content: space-between;
      align-items: baseline;
      font-family: ui-monospace, "SF Mono", monospace;
      font-size: 0.7rem;
      letter-spacing: 0.18em;
      text-transform: uppercase;
      color: #6a5d4a;
    }
    .masthead a { color: #8b2f24; text-decoration: none; }
    .masthead a:hover { text-decoration: underline; }
    .missing {
      max-width: 32rem;
      margin: 8rem auto;
      padding: 0 1.5rem;
      text-align: center;
      color: #4a3e30;
      font-family: ui-serif, Georgia, serif;
    }
    .missing h1 {
      font-size: 2rem;
      font-weight: 600;
      margin: 0 0 0.8rem;
    }
    .missing p { color: #6a5d4a; line-height: 1.6; }
    .missing a { color: #8b2f24; }
  `);

  const doc = usePublishedDoc();
  if (!doc.value) {
    return (
      <div class="missing">
        <h1>The galley is empty</h1>
        <p>
          No published piece is at this URL. The link may be mistyped, or
          the writer has unpublished since.
        </p>
        <p>
          <a href="https://twyne.love">Twyne →</a>
        </p>
      </div>
    );
  }
  const d = doc.value;
  const published = new Date(d.publishedAt).toLocaleDateString(undefined, {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
  return (
    <>
      <article class="reader">
        <h1>{d.title}</h1>
        <p class="byline">
          {d.authorName ? `By ${d.authorName} · ` : ""}Published {published}
        </p>
        {d.briefSummary && <p class="summary">{d.briefSummary}</p>}
        {/* Content is sanitised server-side; rendered as trusted HTML. */}
        <div dangerouslySetInnerHTML={d.content} />
      </article>
      <div class="masthead">
        <span>Set in editorial vermilion</span>
        <Link href="https://twyne.love">Twyne →</Link>
      </div>
    </>
  );
});

export const head: DocumentHead = ({ resolveValue }) => {
  const doc = resolveValue(usePublishedDoc);
  if (!doc) {
    return {
      title: "Not found · Twyne",
    };
  }
  return {
    title: `${doc.title} · Twyne`,
    meta: [
      {
        name: "description",
        content: doc.briefSummary ?? doc.title,
      },
      {
        property: "og:title",
        content: doc.title,
      },
      {
        property: "og:type",
        content: "article",
      },
    ],
  };
};

