import { component$, useStore, $, useStylesScoped$, useVisibleTask$ } from "@builder.io/qwik";
import { Link } from "@builder.io/qwik-city";
import type { Persona } from "../../types";
import { PERSONAS as DEFAULT_PERSONAS } from "../../utils/personas";
import { loadPersonasFromIdb, savePersonasToIdb } from "../../utils/idb";

interface RoomStore {
  personas: Persona[];
  editingId: string | null;
  draftName: string;
  draftRole: string;
  draftDescription: string;
  draftIcon: string;
  adding: boolean;
  newName: string;
  newRole: string;
  newDescription: string;
  newIcon: string;
  showResetConfirm: boolean;
}

export default component$(() => {
  const store = useStore<RoomStore>({
    personas: DEFAULT_PERSONAS,
    editingId: null,
    draftName: "",
    draftRole: "",
    draftDescription: "",
    draftIcon: "",
    adding: false,
    newName: "",
    newRole: "",
    newDescription: "",
    newIcon: "👤",
    showResetConfirm: false,
  });

  // eslint-disable-next-line qwik/no-use-visible-task
  useVisibleTask$(() => {
    loadPersonasFromIdb().then((custom) => {
      if (custom && custom.length > 0) {
        store.personas = custom;
      }
    });
  });

  useStylesScoped$(`
    .room-card {
      border: 1px solid var(--color-paper-3);
      background: var(--color-paper);
      transition: box-shadow 0.2s;
      border-radius: 4px;
    }
    .room-card:hover {
      box-shadow: 0 2px 8px rgba(0,0,0,0.06);
    }
    .room-input {
      width: 100%;
      border: 1px solid var(--color-paper-3);
      background: var(--color-paper-soft);
      padding: 0.5rem 0.75rem;
      color: var(--color-ink);
      border-radius: 2px;
      font-family: var(--font-typewriter);
      font-size: 0.875rem;
    }
    .room-input:focus {
      border-color: var(--color-vermilion);
      outline: none;
    }
    .room-textarea {
      width: 100%;
      border: 1px solid var(--color-paper-3);
      background: var(--color-paper-soft);
      padding: 0.5rem 0.75rem;
      color: var(--color-ink);
      border-radius: 2px;
      font-family: var(--font-typewriter);
      font-size: 0.8175rem;
      resize: vertical;
      min-height: 4rem;
    }
    .room-textarea:focus {
      border-color: var(--color-vermilion);
      outline: none;
    }
  `);

  const persist = $((next: Persona[]) => {
    store.personas = next;
    void savePersonasToIdb(next);
  });

  const startEditing = $((p: Persona) => {
    store.editingId = p.id;
    store.draftName = p.name;
    store.draftRole = p.role;
    store.draftDescription = p.description;
    store.draftIcon = p.icon;
  });

  const saveEdit = $(() => {
    if (!store.editingId) return;
    const next = store.personas.map((p) =>
      p.id === store.editingId
        ? { ...p, name: store.draftName, role: store.draftRole, description: store.draftDescription, icon: store.draftIcon }
        : p,
    );
    store.editingId = null;
    void persist(next);
  });

  const remove = $((id: string) => {
    const next = store.personas.filter((p) => p.id !== id);
    void persist(next);
  });

  const move = $((idx: number, dir: -1 | 1) => {
    const next = [...store.personas];
    const swap = idx + dir;
    if (swap < 0 || swap >= next.length) return;
    [next[idx], next[swap]] = [next[swap], next[idx]];
    void persist(next);
  });

  const addPersona = $(() => {
    if (!store.newName.trim()) return;
    const p: Persona = {
      id: crypto.randomUUID(),
      name: store.newName.trim(),
      role: store.newRole.trim() || "The Editor",
      color: "var(--color-accent)",
      icon: store.newIcon.trim() || "👤",
      description: store.newDescription.trim() || "A sharp, insightful editorial voice.",
      focus: "General editing",
    };
    store.newName = "";
    store.newRole = "";
    store.newDescription = "";
    store.newIcon = "👤";
    store.adding = false;
    void persist([...store.personas, p]);
  });

  const reset = $(() => {
    store.showResetConfirm = true;
  });

  const doReset = $(() => {
    void savePersonasToIdb(DEFAULT_PERSONAS);
    store.personas = DEFAULT_PERSONAS;
    store.showResetConfirm = false;
  });

  return (
    <div class="min-h-screen bg-[var(--color-paper-soft)] text-[var(--color-ink)]" style={{ fontFamily: "var(--font-serif)" }}>
      <div class="max-w-4xl mx-auto px-6 py-8">
        <div class="flex items-center justify-between mb-8">
          <div>
            <p class="dept-label mb-1" style={{ fontFamily: "var(--font-typewriter)" }}>Twyne</p>
            <h1 style={{ fontFamily: "var(--font-display)", fontWeight: 700, fontSize: "1.75rem", color: "var(--color-ink)" }}>
              Room of Editors
            </h1>
            <p class="text-sm text-[var(--color-ink-light)] mt-1" style={{ fontFamily: "var(--font-serif)" }}>
              Add, edit, and arrange your editorial board.
            </p>
          </div>
          <div class="flex items-center gap-3">
            <button
              onClick$={() => { store.adding = true; }}
              class="btn-press text-sm"
              style={{ fontFamily: "var(--font-display)" }}
            >
              + New editor
            </button>
            <button
              onClick$={reset}
              class="btn-paper text-sm"
              style={{ fontFamily: "var(--font-display)" }}
            >
              Reset defaults
            </button>
            <Link
              href="/"
              class="btn-paper text-sm"
              style={{ fontFamily: "var(--font-display)" }}
            >
              ← Back to desk
            </Link>
          </div>
        </div>

        {store.adding && (
          <div class="room-card p-4 mb-6">
            <h3 class="text-sm font-semibold mb-3" style={{ fontFamily: "var(--font-display)", color: "var(--color-accent)" }}>
              New editor
            </h3>
            <div class="grid grid-cols-[auto_1fr] gap-3 items-start">
              <input
                value={store.newIcon}
                onInput$={(e) => { store.newIcon = (e.target as HTMLInputElement).value; }}
                class="room-input w-12 text-center text-lg"
                maxLength={2}
                placeholder="👤"
              />
                <div class="space-y-2">
                <input
                  value={store.newName}
                  onInput$={(e) => { store.newName = (e.target as HTMLInputElement).value; }}
                  placeholder="Editor name"
                  class="room-input"
                />
                <input
                  value={store.newRole}
                  onInput$={(e) => { store.newRole = (e.target as HTMLInputElement).value; }}
                  placeholder="Role (e.g. The Copy Chief)"
                  class="room-input"
                />
                <textarea
                  value={store.newDescription}
                  onInput$={(e) => { store.newDescription = (e.target as HTMLInputElement).value; }}
                  placeholder="Voice description (what perspective do they bring?)"
                  class="room-textarea"
                />
                <div class="flex gap-2">
                  <button onClick$={addPersona} class="btn-press text-xs">Create</button>
                  <button onClick$={() => { store.adding = false; }} class="btn-paper text-xs">Cancel</button>
                </div>
              </div>
            </div>
          </div>
        )}

        {store.showResetConfirm && (
          <div class="room-card p-4 mb-6 bg-[rgba(193,39,45,0.06)]">
            <p class="text-sm text-[var(--color-ink-light)] mb-3" style={{ fontFamily: "var(--font-serif)" }}>
              Reset all editors to the default five? This will discard your changes.
            </p>
            <div class="flex gap-2">
              <button onClick$={doReset} class="btn-press text-xs">Reset</button>
              <button onClick$={() => { store.showResetConfirm = false; }} class="btn-paper text-xs">Cancel</button>
            </div>
          </div>
        )}

        <div class="space-y-3">
          {store.personas.map((p, idx) => {
            const isEditing = store.editingId === p.id;
            return (
              <div key={p.id} class="room-card p-4">
                <div class="flex items-start gap-3">
                  <div class="flex flex-col gap-1 pt-1">
                    <button
                      onClick$={() => move(idx, -1)}
                      disabled={idx === 0}
                      class="text-xs text-[var(--color-ink-muted)] hover:text-[var(--color-ink)] disabled:opacity-20"
                      title="Move up"
                    >
                      ▲
                    </button>
                    <button
                      onClick$={() => move(idx, 1)}
                      disabled={idx === store.personas.length - 1}
                      class="text-xs text-[var(--color-ink-muted)] hover:text-[var(--color-ink)] disabled:opacity-20"
                      title="Move down"
                    >
                      ▼
                    </button>
                  </div>

                  {isEditing ? (
                    <div class="flex-1 grid grid-cols-[auto_1fr] gap-3 items-start">
                      <input
                        value={store.draftIcon}
                        onInput$={(e) => { store.draftIcon = (e.target as HTMLInputElement).value; }}
                        class="room-input w-12 text-center text-lg"
                        maxLength={2}
                      />
                      <div class="space-y-2">
                        <input
                          value={store.draftName}
                          onInput$={(e) => { store.draftName = (e.target as HTMLInputElement).value; }}
                          class="room-input"
                        />
                        <input
                          value={store.draftRole}
                          onInput$={(e) => { store.draftRole = (e.target as HTMLInputElement).value; }}
                          placeholder="Role"
                          class="room-input"
                        />
                        <textarea
                          value={store.draftDescription}
                          onInput$={(e) => { store.draftDescription = (e.target as HTMLInputElement).value; }}
                          class="room-textarea"
                        />
                        <div class="flex gap-2">
                          <button onClick$={saveEdit} class="btn-press text-xs">Save</button>
                          <button onClick$={() => { store.editingId = null; }} class="btn-paper text-xs">Cancel</button>
                        </div>
                      </div>
                    </div>
                  ) : (
                    <div class="flex-1">
                      <div class="flex items-center gap-2 mb-1">
                        <span class="text-xl">{p.icon}</span>
                        <h3 class="text-base font-semibold" style={{ fontFamily: "var(--font-display)", color: "var(--color-ink)" }}>
                          {p.name}
                        </h3>
                      </div>
                      <p class="text-xs text-[var(--color-accent)] mb-1" style={{ fontFamily: "var(--font-typewriter)" }}>
                        {p.role}
                      </p>
                      <p class="text-sm text-[var(--color-ink-light)] leading-relaxed" style={{ fontFamily: "var(--font-serif)" }}>
                        {p.description}
                      </p>
                    </div>
                  )}

                  {!isEditing && (
                    <div class="flex gap-2">
                      <button
                        onClick$={() => startEditing(p)}
                        class="text-xs text-[var(--color-ink-muted)] hover:text-[var(--color-accent)]"
                      >
                        Edit
                      </button>
                      <button
                        onClick$={() => remove(p.id)}
                        class="text-xs text-[var(--color-ink-muted)] hover:text-[var(--color-vermilion)]"
                      >
                        Remove
                      </button>
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        {store.personas.length === 0 && (
          <div class="text-center py-16 text-[var(--color-ink-muted)]">
            <p>No editors on staff.</p>
            <button
              onClick$={() => { store.adding = true; }}
              class="btn-press mt-4 text-sm"
            >
              + Hire your first editor
            </button>
          </div>
        )}
      </div>
    </div>
  );
});

